<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  html, body {
    width: 100%; height: 100%;
    overflow: hidden;
    font-family: 'Ubuntu', 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
    background: #1a1a2e;
    color: #e0e0e0;
    user-select: none;
  }

  /* ── Desktop ── */
  #desktop {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 40%, #0f3460 100%);
    display: flex;
    flex-direction: column;
    z-index: 1;
  }

  /* ── Top Bar ── */
  #topbar {
    height: 28px;
    background: #111;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    font-size: 13px;
    color: #ccc;
    box-shadow: 0 1px 4px rgba(0,0,0,.5);
    z-index: 100;
    flex-shrink: 0;
  }
  #topbar .left { display: flex; align-items: center; gap: 14px; }
  #topbar .right { display: flex; align-items: center; gap: 14px; }
  #topbar .app-name { font-weight: 700; color: #e95420; letter-spacing: .5px; }
  #topbar .clock { font-variant-numeric: tabular-nums; }

  /* ── Taskbar / Dock ── */
  #taskbar {
    position: fixed;
    bottom: 0; left: 0; right: 0;
    height: 52px;
    background: rgba(17,17,17,.92);
    backdrop-filter: blur(12px);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    z-index: 200;
    box-shadow: 0 -2px 10px rgba(0,0,0,.4);
    flex-shrink: 0;
  }
  .dock-btn {
    width: 42px; height: 42px;
    border: none; border-radius: 10px;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    transition: background .15s, transform .1s;
    position: relative;
  }
  .dock-btn:hover { background: rgba(255,255,255,.12); transform: scale(1.08); }
  .dock-btn:active { transform: scale(.95); }
  .dock-btn svg { width: 26px; height: 26px; }
  .dock-btn .dot {
    position: absolute; bottom: -2px; width: 6px; height: 6px;
    border-radius: 50%; background: #e95420;
    opacity: 0; transition: opacity .2s;
  }
  .dock-btn.active .dot { opacity: 1; }

  /* ── Windows ── */
  .app-window {
    position: absolute;
    min-width: 360px; min-height: 240px;
    background: #2d2d2d;
    border-radius: 10px;
    box-shadow: 0 8px 40px rgba(0,0,0,.55), 0 0 0 1px rgba(255,255,255,.06);
    display: none;
    flex-direction: column;
    overflow: hidden;
    z-index: 50;
  }
  .app-window.visible { display: flex; }

  .win-titlebar {
    height: 36px;
    background: #3a3a3a;
    display: flex;
    align-items: center;
    padding: 0 10px;
    cursor: grab;
    flex-shrink: 0;
    border-bottom: 1px solid #222;
  }
  .win-titlebar:active { cursor: grabbing; }
  .win-title {
    flex: 1;
    text-align: center;
    font-size: 13px;
    font-weight: 600;
    color: #ddd;
    pointer-events: none;
  }
  .win-close {
    width: 28px; height: 28px;
    border: none; border-radius: 50%;
    background: #e95420;
    color: #fff;
    font-size: 16px;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    transition: background .15s;
    line-height: 1;
  }
  .win-close:hover { background: #c7431b; }

  .win-body { flex: 1; overflow: auto; display: flex; flex-direction: column; }

  /* ── Files App ── */
  #files-window { width: 680px; height: 460px; }
  #files-toolbar {
    display: flex; align-items: center; gap: 8px;
    padding: 6px 10px;
    background: #333;
    border-bottom: 1px solid #222;
    flex-shrink: 0;
  }
  #files-up {
    width: 30px; height: 30px;
    border: none; border-radius: 6px;
    background: #444; color: #ddd;
    cursor: pointer; font-size: 16px;
    display: flex; align-items: center; justify-content: center;
    transition: background .15s;
  }
  #files-up:hover { background: #555; }
  #files-path {
    flex: 1;
    background: #1e1e1e;
    border: 1px solid #444;
    border-radius: 6px;
    padding: 4px 10px;
    color: #ddd;
    font-size: 13px;
    font-family: 'Ubuntu Mono', 'Fira Code', monospace;
    outline: none;
  }
  #files-path:focus { border-color: #e95420; }
  #files-list {
    flex: 1;
    padding: 10px;
    display: flex;
    flex-wrap: wrap;
    align-content: flex-start;
    gap: 6px;
    overflow-y: auto;
  }
  .fs-item {
    width: 90px;
    padding: 8px 4px;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    border-radius: 8px;
    cursor: pointer;
    transition: background .12s;
    text-align: center;
  }
  .fs-item:hover { background: rgba(255,255,255,.08); }
  .fs-item .icon { font-size: 32px; line-height: 1; }
  .fs-item .name { font-size: 11px; color: #ccc; word-break: break-all; }
  .fs-item.folder .icon { color: #e95420; }
  .fs-item.file .icon { color: #58a6ff; }

  /* ── Notepad App ── */
  #notepad-window { width: 640px; height: 440px; }
  #notepad-toolbar {
    display: flex; align-items: center; gap: 6px;
    padding: 6px 10px;
    background: #333;
    border-bottom: 1px solid #222;
    flex-shrink: 0;
  }
  #new-tab {
    height: 28px;
    border: none; border-radius: 6px;
    background: #e95420; color: #fff;
    cursor: pointer; font-size: 13px; font-weight: 600;
    padding: 0 12px;
    display: flex; align-items: center; justify-content: center;
    transition: background .15s;
  }
  #new-tab:hover { background: #c7431b; }
  #tabs {
    flex: 1;
    display: flex;
    align-items: stretch;
    background: #2a2a2a;
    overflow-x: auto;
    border-bottom: 1px solid #222;
    flex-shrink: 0;
  }
  .tab {
    padding: 6px 16px;
    font-size: 12px;
    color: #999;
    cursor: pointer;
    border-right: 1px solid #333;
    display: flex; align-items: center; gap: 6px;
    white-space: nowrap;
    transition: background .12s, color .12s;
    flex-shrink: 0;
    position: relative;
  }
  .tab:hover { background: rgba(255,255,255,.06); color: #ccc; }
  .tab.active { background: #3a3a3a; color: #e95420; font-weight: 600; }
  .tab .tab-close {
    width: 16px; height: 16px;
    border: none; border-radius: 50%;
    background: transparent; color: #888;
    cursor: pointer; font-size: 12px;
    display: flex; align-items: center; justify-content: center;
    transition: background .12s, color .12s;
    line-height: 1;
  }
  .tab .tab-close:hover { background: #e95420; color: #fff; }
  #editor-wrap { flex: 1; display: flex; flex-direction: column; overflow: hidden; }
  #editor {
    flex: 1;
    width: 100%;
    background: #1e1e1e;
    color: #d4d4d4;
    border: none;
    padding: 12px;
    font-family: 'Ubuntu Mono', 'Fira Code', 'Consolas', monospace;
    font-size: 14px;
    line-height: 1.6;
    resize: none;
    outline: none;
    tab-size: 4;
  }
  #editor::selection { background: #e95420; color: #fff; }

  /* scrollbar */
  ::-webkit-scrollbar { width: 8px; height: 8px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: #555; border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: #777; }
</style>
</head>
<body>

<!-- Desktop -->
<div id="desktop">

  <!-- Top Bar -->
  <div id="topbar">
    <div class="left">
      <span class="app-name">Ubuntu</span>
    </div>
    <div class="right">
      <span class="clock" id="clock"></span>
    </div>
  </div>

  <!-- Taskbar / Dock -->
  <div id="taskbar">
    <button class="dock-btn" id="open-files" title="Files">
      <svg viewBox="0 0 24 24" fill="none" stroke="#e95420" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">
        <path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/>
      </svg>
      <span class="dot"></span>
    </button>
    <button class="dock-btn" id="open-notepad" title="Notepad">
      <svg viewBox="0 0 24 24" fill="none" stroke="#58a6ff" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">
        <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
        <polyline points="14 2 14 8 20 8"/>
        <line x1="16" y1="13" x2="8" y2="13"/>
        <line x1="16" y1="17" x2="8" y2="17"/>
        <polyline points="10 9 9 9 8 9"/>
      </svg>
      <span class="dot"></span>
    </button>
  </div>

  <!-- Files Window -->
  <div class="app-window" id="files-window">
    <div class="win-titlebar" id="files-titlebar">
      <span class="win-title">Files</span>
      <button class="win-close" aria-label="Close">✕</button>
    </div>
    <div class="win-body">
      <div id="files-toolbar">
        <button id="files-up" title="Up">↑</button>
        <input id="files-path" type="text" readonly>
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div class="app-window" id="notepad-window">
    <div class="win-titlebar" id="notepad-titlebar">
      <span class="win-title">Notepad</span>
      <button class="win-close" aria-label="Close">✕</button>
    </div>
    <div class="win-body">
      <div id="notepad-toolbar">
        <button id="new-tab">+ New Tab</button>
      </div>
      <div id="tabs"></div>
      <div id="editor-wrap">
        <textarea id="editor" spellcheck="false"></textarea>
      </div>
    </div>
  </div>

</div>

<script>
(function() {
  "use strict";

  /* ── Clock ── */
  const clockEl = document.getElementById('clock');
  function updateClock() {
    const d = new Date();
    clockEl.textContent = d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) + '  ' +
      d.toLocaleDateString([], { weekday: 'short', month: 'short', day: 'numeric' });
  }
  updateClock();
  setInterval(updateClock, 30000);

  /* ── Dock active indicators ── */
  const filesBtn = document.getElementById('open-files');
  const notepadBtn = document.getElementById('open-notepad');
  const filesWin = document.getElementById('files-window');
  const notepadWin = document.getElementById('notepad-window');

  function toggleWindow(win, btn) {
    if (win.classList.contains('visible')) {
      win.classList.remove('visible');
      btn.classList.remove('active');
    } else {
      win.classList.add('visible');
      btn.classList.add('active');
    }
  }

  document.getElementById('open-files').addEventListener('click', function() {
    toggleWindow(filesWin, filesBtn);
  });
  document.getElementById('open-notepad').addEventListener('click', function() {
    toggleWindow(notepadWin, notepadBtn);
  });

  /* ── Close buttons ── */
  filesWin.querySelector('.win-close').addEventListener('click', function() {
    filesWin.classList.remove('visible');
    filesBtn.classList.remove('active');
  });
  notepadWin.querySelector('.win-close').addEventListener('click', function() {
    notepadWin.classList.remove('visible');
    notepadBtn.classList.remove('active');
  });

  /* ── Draggable windows ── */
  function makeDraggable(win, titlebar) {
    let startX, startY, origX, origY, dragging = false;
    titlebar.addEventListener('mousedown', function(e) {
      if (e.target.classList.contains('win-close')) return;
      dragging = true;
      startX = e.clientX; startY = e.clientY;
      origX = win.offsetLeft; origY = win.offsetTop;
      e.preventDefault();
    });
    document.addEventListener('mousemove', function(e) {
      if (!dragging) return;
      win.style.left = (origX + e.clientX - startX) + 'px';
      win.style.top = (origY + e.clientY - startY) + 'px';
      win.style.right = 'auto';
      win.style.bottom = 'auto';
    });
    document.addEventListener('mouseup', function() { dragging = false; });
  }
  makeDraggable(filesWin, document.getElementById('files-titlebar'));
  makeDraggable(notepadWin, document.getElementById('notepad-titlebar'));

  /* ── Files App ── */
  const fileSystem = {
    '/': ['bin', 'etc', 'home', 'usr', 'var'],
    '/bin': ['bash', 'ls', 'cat', 'cp', 'mv', 'rm'],
    '/etc': ['passwd', 'hostname', 'fstab', 'resolv.conf'],
    '/home': ['user'],
    '/home/user': ['Documents', 'Downloads', 'Pictures', '.bashrc', '.profile'],
    '/home/user/Documents': ['readme.txt', 'notes.md'],
    '/home/user/Downloads': ['archive.tar.gz', 'setup.deb'],
    '/home/user/Pictures': ['wallpaper.png', 'screenshot.png'],
    '/usr': ['bin', 'lib', 'share', 'local'],
    '/usr/bin': ['python3', 'gcc', 'make', 'git'],
    '/usr/lib': ['libc.so', 'libssl.so'],
    '/usr/share': ['doc', 'man', 'locale'],
    '/var': ['log', 'tmp', 'cache'],
    '/var/log': ['syslog', 'auth.log', 'kern.log'],
    '/var/tmp': [],
    '/var/cache': []
  };

  let currentPath = '/';

  const filesPath = document.getElementById('files-path');
  const filesList = document.getElementById('files-list');
  const filesUp = document.getElementById('files-up');

  function renderFiles() {
    filesPath.value = currentPath;
    filesList.innerHTML = '';
    const entries = fileSystem[currentPath] || [];
    if (entries.length === 0) {
      const empty = document.createElement('div');
      empty.style.cssText = 'width:100%;text-align:center;color:#666;padding:40px;font-size:14px;';
      empty.textContent = 'Empty folder';
      filesList.appendChild(empty);
      return;
    }
    // Sort: folders first, then files
    const folders = entries.filter(e => fileSystem[currentPath + '/' + e] !== undefined).sort();
    const files = entries.filter(e => fileSystem[currentPath + '/' + e] === undefined).sort();
    const sorted = [...folders, ...files];

    sorted.forEach(name => {
      const isFolder = fileSystem[currentPath + '/' + name] !== undefined;
      const item = document.createElement('div');
      item.className = 'fs-item' + (isFolder ? ' folder' : ' file');
      item.innerHTML = '<span class="icon">' + (isFolder ? '📁' : '📄') + '</span><span class="name">' + name + '</span>';

      item.addEventListener('dblclick', function() {
        if (isFolder) {
          currentPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
          renderFiles();
        }
      });
      filesList.appendChild(item);
    });
  }

  filesUp.addEventListener('click', function() {
    if (currentPath === '/') return;
    const parts = currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath = '/' + parts.join('/');
    if (currentPath === '') currentPath = '/';
    renderFiles();
  });

  renderFiles();

  /* ── Notepad App ── */
  const STORAGE_KEY = 'ubuntu-notepad-tabs';
  const tabsEl = document.getElementById('tabs');
  const editor = document.getElementById('editor');
  const newTabBtn = document.getElementById('new-tab');

  let tabs = [];
  let activeTabId = null;

  function generateId() {
    return 'tab_' + Date.now() + '_' + Math.random().toString(36).substr(2, 5);
  }

  function saveTabs() {
    const data = tabs.map(function(t) { return { id: t.id, name: t.name, content: t.content }; });
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  }

  function loadTabs() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        tabs = JSON.parse(raw);
        if (tabs.length > 0) {
          activeTabId = tabs[0].id;
        }
      }
    } catch(e) {
      tabs = [];
    }
    if (tabs.length === 0) {
      addTab('Untitled');
    }
  }

  function addTab(name) {
    const id = generateId();
    tabs.push({ id: id, name: name || 'Untitled', content: '' });
    activeTabId = id;
    saveTabs();
    renderTabs();
    updateEditor();
  }

  function removeTab(id) {
    const idx = tabs.findIndex(function(t) { return t.id === id; });
    if (idx === -1) return;
    tabs.splice(idx, 1);
    if (activeTabId === id) {
      if (tabs.length > 0) {
        activeTabId = tabs[Math.min(idx, tabs.length - 1)].id;
      } else {
        addTab('Untitled');
        return;
      }
    }
    saveTabs();
    renderTabs();
    updateEditor();
  }

  function activateTab(id) {
    // Save current tab content first
    if (activeTabId) {
      const cur = tabs.find(function(t) { return t.id === activeTabId; });
      if (cur) cur.content = editor.value;
    }
    activeTabId = id;
    renderTabs();
    updateEditor();
  }

  function updateEditor() {
    const tab = tabs.find(function(t) { return t.id === activeTabId; });
    if (tab) {
      editor.value = tab.content;
    }
  }

  function renderTabs() {
    tabsEl.innerHTML = '';
    tabs.forEach(function(t) {
      const el = document.createElement('div');
      el.className = 'tab' + (t.id === activeTabId ? ' active' : '');
      el.innerHTML = '<span class="tab-name">' + escapeHtml(t.name) + '</span>' +
        '<button class="tab-close" title="Close tab">✕</button>';
      el.querySelector('.tab-name').addEventListener('click', function() {
        activateTab(t.id);
      });
      el.querySelector('.tab-close').addEventListener('click', function(e) {
        e.stopPropagation();
        removeTab(t.id);
      });
      tabsEl.appendChild(el);
    });
  }

  function escapeHtml(str) {
    return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  newTabBtn.addEventListener('click', function() {
    addTab('Untitled');
  });

  editor.addEventListener('input', function() {
    const tab = tabs.find(function(t) { return t.id === activeTabId; });
    if (tab) {
      tab.content = editor.value;
      saveTabs();
    }
  });

  // Tab key support in editor
  editor.addEventListener('keydown', function(e) {
    if (e.key === 'Tab') {
      e.preventDefault();
      const start = this.selectionStart;
      const end = this.selectionEnd;
      this.value = this.value.substring(0, start) + '    ' + this.value.substring(end);
      this.selectionStart = this.selectionEnd = start + 4;
      this.dispatchEvent(new Event('input'));
    }
  });

  /* ── Initialize Notepad ── */
  loadTabs();
  renderTabs();
  updateEditor();

})();
</script>
</body>
</html>
